# Utility functions for shape operations

from shapes import Shape, Rectangle, Circle, Square

def scale_shape(shape: Shape, factor: float) -> Shape:
    if isinstance(shape, Rectangle):
        rect: Rectangle = shape
        return Rectangle(rect.width * factor, rect.height * factor)
    elif isinstance(shape, Square):
        sq: Square = shape
        new_side: float = sq.width * factor
        return Square(new_side)
    elif isinstance(shape, Circle):
        circ: Circle = shape
        return Circle(circ.radius * factor)
    return shape

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total
